import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AppraisalForm.css";

export default function AppraisalForm() {

  const navigate = useNavigate();
  const { id } = useParams();

  /* ===============================
     GET LOGGED USER
  =============================== */
  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || {};

  const role =
    loggedUser?.role?.toUpperCase() || "EMPLOYEE";

  const token =
    localStorage.getItem("token");

  const base =
    role === "ADMIN"
      ? "/admin-dashboard"
      : "/employee-dashboard";

  /* ===============================
     STATE
  =============================== */
  const [employees, setEmployees] = useState([]);

  const [formData, setFormData] = useState({
    employeeName: "",
    department: "",
    period: "Jan 2024 - Dec 2024",
    rating: "",
    status: "Pending"
  });

  const [errors, setErrors] = useState({});


  /* ===============================
     LOAD EMPLOYEES BASED ON ROLE
  =============================== */
  useEffect(() => {

    const loadEmployees = async () => {

      try {

        /* ADMIN → load all employees */
        if (role === "ADMIN") {

          const res =
            await fetch(
              "http://localhost:8080/api/employees",
              {
                headers: {
                  Authorization: `Bearer ${token}`
                }
              }
            );

          if (!res.ok)
            throw new Error("Failed");

          const data = await res.json();

          setEmployees(data);

        }

        /* EMPLOYEE → load only own profile */
        else {

          const res =
            await fetch(
              "http://localhost:8080/api/profile",
              {
                headers: {
                  Authorization: `Bearer ${token}`
                }
              }
            );

          if (!res.ok)
            throw new Error("Failed");

          const data = await res.json();

          setEmployees([{
            id: data.id,
            firstName:
              data.email.split("@")[0],
            lastName: "",
            department:
              data.department
          }]);

        }

      }
      catch (err) {

        console.error(
          "Employee load error:",
          err
        );

      }

    };

    loadEmployees();

  }, [role, token]);


  /* ===============================
     LOAD APPRAISAL FOR EDIT
  =============================== */
  useEffect(() => {

    if (!id) return;

    const load = async () => {

      try {

        const res =
          await fetch(
            `http://localhost:8080/api/appraisals/${id}`,
            {
              headers: {
                Authorization: `Bearer ${token}`
              }
            }
          );

        const data =
          await res.json();

        setFormData({

          employeeName:
            data.employeeName,

          department:
            data.department,

          period:
            data.reviewPeriod,

          rating:
            data.rating,

          status:
            data.status

        });

      }
      catch (err) {

        console.error(err);

      }

    };

    load();

  }, [id, token]);


  /* ===============================
     HANDLE CHANGE
  =============================== */
  const handleChange = (e) => {

    const { name, value } = e.target;

    if (name === "employeeName") {

      const emp =
        employees.find(
          e =>
            `${e.firstName} ${e.lastName}`.trim()
            === value
        );

      setFormData({
        ...formData,
        employeeName: value,
        department: emp?.department || ""
      });

      return;
    }

    setFormData({
      ...formData,
      [name]: value
    });

  };


  /* ===============================
     VALIDATION
  =============================== */
  const validate = () => {

    let temp = {};

    if (!formData.employeeName)
      temp.employeeName =
        "Employee required";

    if (!formData.rating)
      temp.rating =
        "Rating required";

    setErrors(temp);

    return Object.keys(temp).length === 0;

  };


  /* ===============================
     SUBMIT
  =============================== */
  const handleSubmit = async (e) => {

    e.preventDefault();

    if (!validate()) return;

    try {

      const method =
        id ? "PUT" : "POST";

      const url =
        id
          ? `http://localhost:8080/api/appraisals/${id}`
          : `http://localhost:8080/api/appraisals`;

      await fetch(url, {

        method,

        headers: {
          "Content-Type":
            "application/json",
          Authorization:
            `Bearer ${token}`
        },

        body:
          JSON.stringify({

            employeeName:
              formData.employeeName,

            department:
              formData.department,

            reviewPeriod:
              formData.period,

            rating:
              parseFloat(formData.rating),

            status:
              formData.status,

            remarks: "",

            salaryIncrease: 0

          })

      });

      alert("Saved Successfully");

      navigate(`${base}/appraisal`);

    }
    catch (err) {

      console.error(err);

    }

  };


  /* ===============================
     UI
  =============================== */
  return (

    <div className="appraisal-form-scope">

      <div className="appraisal-form-card">

        <h2>
          {id
            ? "Edit Employee Appraisal"
            : "Add Employee Appraisal"}
        </h2>

        <form onSubmit={handleSubmit}>

          <label>Employee Name</label>

          <select
            name="employeeName"
            value={formData.employeeName}
            onChange={handleChange}
          >

            <option value="">
              Select Employee
            </option>

            {employees.map(emp => (

              <option key={emp.id}>
                {`${emp.firstName} ${emp.lastName}`.trim()}
              </option>

            ))}

          </select>

          <label>Department</label>

          <input
            value={formData.department}
            disabled
          />

          <label>Review Period</label>

          <input
            name="period"
            value={formData.period}
            onChange={handleChange}
          />

          <label>Rating</label>

          <input
            type="number"
            name="rating"
            value={formData.rating}
            onChange={handleChange}
          />

          <label>Status</label>

          <select
            name="status"
            value={formData.status}
            onChange={handleChange}
          >
            <option>Pending</option>
            <option>Approved</option>
            <option>Rejected</option>
          </select>

          <div className="appraisal-btn-row">

            <button type="submit">
              Save
            </button>

            <button
              type="button"
              onClick={() =>
                navigate(`${base}/appraisal`)
              }
            >
              Cancel
            </button>

          </div>

        </form>

      </div>

    </div>

  );

}
